export function nextGeneration(livingCells: [number, number][]): [number, number][] {
  if (livingCells.length === 0) return [];

  const alive = new Set(livingCells.map(([x, y]) => `${x},${y}`));
  const candidates = new Set<string>();

  for (const [x, y] of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        candidates.add(`${x + dx},${y + dy}`);
      }
    }
  }

  const result: [number, number][] = [];

  for (const key of candidates) {
    const [x, y] = key.split(",").map(Number);
    let neighbors = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (alive.has(`${x + dx},${y + dy}`)) neighbors++;
      }
    }
    if (alive.has(key)) {
      if (neighbors === 2 || neighbors === 3) result.push([x, y]);
    } else {
      if (neighbors === 3) result.push([x, y]);
    }
  }

  return result;
}

